# config_parity.py - Stage 2: Diff staging vs production config
# Usage: python config_parity.py --staging-url https://staging.example.com --prod-url https://api.prod.example.com

import argparse
import sys
import httpx

# Keys expected to differ between environments - do not flag these.
ALLOWED_DIFFS = {"base_url", "log_level", "replica_count"}


def fetch_config(base_url: str, api_key: str) -> dict:
    """Fetch the /config/inspect endpoint that exposes non-secret config."""
    resp = httpx.get(
        f"{base_url}/config/inspect",
        headers={"Authorization": f"Bearer {api_key}"},
        timeout=15,
    )
    resp.raise_for_status()
    return resp.json()


def diff_configs(staging: dict, prod: dict, path: str = "") -> list[str]:
    """Recursively diff two config dicts; return list of unexpected differences."""
    diffs = []
    all_keys = set(staging) | set(prod)
    for key in sorted(all_keys):
        full_key = f"{path}.{key}" if path else key
        if key not in staging:
            diffs.append(f"MISSING in staging: {full_key} = {prod[key]!r}")
        elif key not in prod:
            diffs.append(f"MISSING in prod:    {full_key} = {staging[key]!r}")
        elif isinstance(staging[key], dict) and isinstance(prod[key], dict):
            diffs.extend(diff_configs(staging[key], prod[key], full_key))
        elif staging[key] != prod[key]:
            if full_key not in ALLOWED_DIFFS:
                diffs.append(
                    f"MISMATCH: {full_key}  staging={staging[key]!r}  prod={prod[key]!r}"
                )
    return diffs


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--staging-url", required=True)
    parser.add_argument("--prod-url", required=True)
    parser.add_argument("--staging-key", default="staging-api-key")
    parser.add_argument("--prod-key", default="prod-api-key")
    args = parser.parse_args()

    staging_cfg = fetch_config(args.staging_url, args.staging_key)
    prod_cfg = fetch_config(args.prod_url, args.prod_key)

    diffs = diff_configs(staging_cfg, prod_cfg)
    if diffs:
        print(f"Config parity FAILED - {len(diffs)} unexpected difference(s):")
        for d in diffs:
            print(f"  {d}")
        sys.exit(1)
    else:
        print("Config parity PASSED - staging matches prod (ignoring allowed keys).")


if __name__ == "__main__":
    main()
